namespace sv_48f417de89214cb98fb8e5d29cb54c82.Services;

public sealed record Recipe(int Id, string Title, string Description, int PrepTimeMinutes);

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> Recipes = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic pizza with tomato sauce, mozzarella, and basil.", 30),
            new(2, "Spaghetti Carbonara", "Pasta with egg, pecorino romano, guanciale, and black pepper.", 25),
            new(3, "Tiramisu", "Layered coffee-flavored dessert with mascarpone cream.", 45),
        },
        [2] = new List<Recipe>
        {
            new(4, "Kung Pao Chicken", "Spicy stir-fried chicken with peanuts and vegetables.", 35),
            new(5, "Mapo Tofu", "Silken tofu in a spicy, numbing chili and bean paste sauce.", 20),
            new(6, "Char Siu", "Cantonese-style barbecued pork with honey glaze.", 60),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Marinated pork tacos with pineapple and cilantro.", 40),
            new(8, "Guacamole", "Fresh avocado dip with lime, onion, and jalapeño.", 10),
            new(9, "Churros", "Fried dough pastry coated in cinnamon sugar.", 30),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        return Recipes.TryGetValue(cuisineId, out var recipes)
            ? recipes
            : new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@implements IDisposable
@inject IRecipeService RecipeService
@inject NavigationManager Navigation
@inject ILogger<Recipes> Logger

<PageTitle>Recipes</PageTitle>

<h1>Recipes — Cuisine @CuisineId</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger btn-sm" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <div class="alert alert-info py-1 px-2 d-inline-block" role="status">Refreshing…</div>
    }

    @if (_recipes.Count == 0)
    {
        <p>No recipes found for this cuisine.</p>
    }
    else
    {
        <table class="table">
            <thead>
                <tr>
                    <th>Title</th>
                    <th>Description</th>
                    <th>Prep Time (min)</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var recipe in DisplayRecipes)
                {
                    <tr>
                        <td>@recipe.Title</td>
                        <td>@recipe.Description</td>
                        <td>@recipe.PrepTimeMinutes</td>
                    </tr>
                }
            </tbody>
        </table>
    }
}

@code {
    [Parameter] public int CuisineId { get; set; }
    [SupplyParameterFromQuery(Name = "sort")] public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private bool _isRefreshing;
    private string? _error;

    private int _loadedCuisineId;
    private CancellationTokenSource? _loadCts;
    private readonly CancellationTokenSource _disposeCts = new();

    private IReadOnlyList<Recipe> DisplayRecipes =>
        _recipes is null
            ? Array.Empty<Recipe>()
            : string.Equals(Sort, "popular", StringComparison.OrdinalIgnoreCase)
                ? _recipes.OrderByDescending(r => r.PrepTimeMinutes).ToList()
                : _recipes.OrderBy(r => r.Id).ToList();

    protected override Task OnParametersSetAsync()
    {
        if (CuisineId == _loadedCuisineId)
        {
            // Only sort changed — no reload needed.
            return Task.CompletedTask;
        }

        return LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight load for a previous cuisine.
        await CancelPendingLoadAsync();

        _loadedCuisineId = CuisineId;
        _error = null;
        _isRefreshing = _recipes is not null;

        var cts = CancellationTokenSource.CreateLinkedTokenSource(_disposeCts.Token);
        _loadCts = cts;

        try
        {
            var result = await RecipeService.GetByCuisineAsync(CuisineId, cts.Token);

            if (cts.Token.IsCancellationRequested)
                return;

            _recipes = result;
        }
        catch (OperationCanceledException) when (cts.Token.IsCancellationRequested)
        {
            // Load was intentionally cancelled — nothing to do.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "Something went wrong while loading recipes. Please try again.";
        }
        finally
        {
            _isRefreshing = false;
        }
    }

    private async Task RetryAsync() => await LoadRecipesAsync();

    private async Task CancelPendingLoadAsync()
    {
        if (_loadCts is not null)
        {
            await _loadCts.CancelAsync();
            _loadCts.Dispose();
            _loadCts = null;
        }
    }

    public void Dispose()
    {
        _disposeCts.Cancel();
        _disposeCts.Dispose();
        _loadCts?.Dispose();
    }
}

